import type {
  FilterFieldDuration,
  FilterFieldKeySuggestionConfig,
  FilterFieldKeySuggestionGroupConfig,
  FilterFieldValidatorMapTypePredicate,
  FilterFieldRichValuePredicate,
  FilterFieldValueSuggestionGroupConfig,
} from '../../types/validation.js';

/**
 * Check whether the given value specification is a type specification.
 * @internal
 */
export function isFilterFieldValidatorMapTypeSpecification(
  valueSpecification: unknown,
  // DEPRECATION: [APPDEV-16872] BREAKING-CHANGE
  // eslint-disable-next-line @typescript-eslint/no-deprecated
): valueSpecification is FilterFieldValidatorMapTypePredicate {
  return (
    typeof valueSpecification === 'object' &&
    valueSpecification !== null &&
    'type' in valueSpecification &&
    !('value' in valueSpecification)
  );
}

/**
 * Check whether the given value specification is a duration specification.
 * @internal
 */
export function isFilterFieldValidatorMapDurationSpecification(
  valueSpecification: unknown,
  // DEPRECATION: [APPDEV-16872] BREAKING-CHANGE
  // eslint-disable-next-line @typescript-eslint/no-deprecated
): valueSpecification is FilterFieldDuration {
  // DEPRECATION: [APPDEV-16872] BREAKING-CHANGE
  // eslint-disable-next-line @typescript-eslint/no-deprecated
  const castedValueSpecification = valueSpecification as FilterFieldDuration;

  return (
    typeof valueSpecification === 'object' &&
    castedValueSpecification.value !== undefined &&
    castedValueSpecification.unit !== undefined
  );
}

/**
 * Check whether the given value specification is a value predicate with metadata.
 * @internal
 */
export function isFilterFieldRichValuePredicate(
  valueSpecification: unknown,
): valueSpecification is FilterFieldRichValuePredicate {
  const castedValueSpecification =
    valueSpecification as FilterFieldRichValuePredicate;

  return (
    typeof valueSpecification === 'object' &&
    castedValueSpecification !== null &&
    'value' in castedValueSpecification &&
    !isFilterFieldValidatorMapTypeSpecification(valueSpecification) &&
    ('displayValue' in castedValueSpecification ||
      'details' in castedValueSpecification)
  );
}

/**
 * Check whether the given value is a key suggestion config (has a `key` string property).
 * @internal
 */
export function isFilterFieldKeySuggestionConfig(
  value: unknown,
): value is FilterFieldKeySuggestionConfig {
  return (
    typeof value === 'object' &&
    value !== null &&
    'key' in value &&
    typeof (value as FilterFieldKeySuggestionConfig).key === 'string'
  );
}

/**
 * Check whether the given value is a key suggestion group config (has a `suggestions` array and no `key` property).
 * @internal
 */
export function isFilterFieldKeySuggestionGroupConfig(
  value: unknown,
): value is FilterFieldKeySuggestionGroupConfig {
  return (
    typeof value === 'object' &&
    value !== null &&
    'suggestions' in value &&
    Array.isArray((value as FilterFieldKeySuggestionGroupConfig).suggestions) &&
    !('key' in value)
  );
}

/**
 * Check whether the given value is a value suggestion group config (has a `suggestions` array).
 * @internal
 */
export function isFilterFieldValueSuggestionGroupConfig(
  value: unknown,
): value is FilterFieldValueSuggestionGroupConfig {
  return (
    typeof value === 'object' &&
    value !== null &&
    'suggestions' in value &&
    Array.isArray((value as FilterFieldValueSuggestionGroupConfig).suggestions)
  );
}
